parameters.jsCode:
const output = [];

for (const item of $input.all()) {
  const notionDateTimeRaw = item.json.properties?.["Publish Date"]?.date?.start;

  let notionDateOnly = null;
  let notionTimeOnly = null;

  if (notionDateTimeRaw) {
    // Extract date and time from ISO string manually to keep UTC+2
    const [datePart, timePartWithZone] = notionDateTimeRaw.split("T");
    const timePart = timePartWithZone.split("+")[0].split(".")[0]; // clean from +02:00 and milliseconds
    notionDateOnly = datePart;
    notionTimeOnly = timePart;
  }

  const triggerTimestamp = item.json["Schedule Trigger"]?.timestamp || new Date().toISOString();
  const triggerDate = new Date(triggerTimestamp);
  const triggerDateOnly = triggerDate.toISOString().split("T")[0];
  const triggerTimeOnly = triggerDate.toTimeString().split(" ")[0];

  output.push({
    notionDate: notionDateOnly,
    notionTime: notionTimeOnly,
    triggerDate: triggerDateOnly,
    triggerTime: triggerTimeOnly
  });
}

return output;

